input.command:
echo 'import json
from datetime import datetime, timedelta

with open("/tmp/all_tickets.json") as f:
    tickets = json.load(f)

def week_label(dt):
    monday = dt - timedelta(days=dt.weekday())
    sunday = monday + timedelta(days=6)
    return monday.strftime("%b %d") + " - " + sunday.strftime("%b %d")

all_by_week = {}
esc_by_week = {}

for t in tickets:
    dt = datetime.fromisoformat(t["created_at"].replace("Z", "+00:00"))
    wl = week_label(dt)
    all_by_week[wl] = all_by_week.get(wl, 0) + 1
    if t["status"] == "escalated":
        esc_by_week[wl] = esc_by_week.get(wl, 0) + 1

weeks_sorted = sorted(all_by_week.keys(), key=lambda w: datetime.strptime(w.split(" - ")[0], "%b %d"))

for w in weeks_sorted:
    total = all_by_week[w]
    esc = esc_by_week.get(w, 0)
    rate = (esc / total * 100) if total > 0 else 0
    print(w + " | " + str(total) + " total | " + str(esc) + " escalated | " + str(round(rate)) + " pct")
' > /tmp/analyze_tickets.py

